const item = $input.first().json;
return [{ json: {
  body: {
    niche: item.niche || item.Niche || '',
    niche_cluster: item.niche_cluster || 'commercial_local',
    city: item.city || item.City || '',
    project_id: item.project_id || item.ProjectId || '',
    project_phase: item.project_phase || 'growth',
    target_url: item.target_url || '',
    competitors: item.competitors ? 
      (typeof item.competitors === 'string' ? JSON.parse(item.competitors) : item.competitors) : []
  }
}}];

const body = $input.first().json.body || $input.first().json;
let { niche, niche_cluster, city, project_id, project_phase, target_url, competitors } = body;

const sanitize = (s, maxLen = 200) => {
  if (!s || typeof s !== 'string') return '';
  return s.replace(/<[^>]*>/g, '').replace(/[\x00-\x1F]/g, '').trim().substring(0, maxLen);
};

niche = sanitize(niche);
city = sanitize(city, 100);
project_id = sanitize(project_id, 50);
niche_cluster = sanitize(niche_cluster, 30) || 'commercial_local';
project_phase = sanitize(project_phase, 20) || 'growth';

if (!niche) throw new Error('Поле "niche" обязательно');
if (!city) throw new Error('Поле "city" обязательно');
if (!project_id) throw new Error('Поле "project_id" обязательно');

const validClusters = ['commercial_local','commercial_national','ecom','saas','info'];
if (!validClusters.includes(niche_cluster)) niche_cluster = 'commercial_local';

const validPhases = ['setup','growth','maintenance','recovery'];
if (!validPhases.includes(project_phase)) project_phase = 'growth';

const urlRegex = /^https?:\/\/[\w.-]+\.[a-z]{2,}/i;
let competitorsList = [];
if (Array.isArray(competitors)) {
  competitorsList = competitors.filter(u => typeof u === 'string' && urlRegex.test(u)).slice(0, 5);
}
if (target_url && !urlRegex.test(target_url)) target_url = '';

const embed_query = niche + ' ' + city + ' E-E-A-T ' + niche_cluster;

return [{ json: {
  niche, niche_cluster, city, project_id, project_phase,
  target_url: target_url || '',
  competitors: competitorsList,
  embed_query,
  is_cron_trigger: $execution.mode === 'trigger',
  workflow_version: 'v4.0_pro',
  run_id: $execution.id,
  started_at: new Date().toISOString()
}}];

const collections = [
  { node: 'RAG seo_personas', label: 'ЦЕЛЕВАЯ АУДИТОРИЯ', prefix: 'Персона' },
  { node: 'RAG page_structures', label: 'СТРУКТУРЫ СТРАНИЦ ТОП-10', prefix: 'Проект' },
  { node: 'RAG eeat_history', label: 'ИСТОРИЯ E-E-A-T АНАЛИЗОВ', prefix: 'Анализ' },
  { node: 'RAG competitor_eeat', label: 'КОНКУРЕНТНЫЕ E-E-A-T СИГНАЛЫ', prefix: 'Конкурент' }
];

let ragContext = '';
let totalSources = 0;
const sourceCounts = {};

for (const col of collections) {
  let results = [];
  try { results = $(col.node).first().json.result || []; } catch(e) {}

  // Sort by relevance score desc
  results.sort((a, b) => (b.score || 0) - (a.score || 0));

  sourceCounts[col.node] = results.length;
  totalSources += results.length;

  if (results.length > 0) {
    ragContext += '\n=== ' + col.label + ' (' + results.length + ' sources) ===\n\n';
    results.forEach((r, i) => {
      const p = r.payload || {};
      const score = r.score ? ` [relevance: ${r.score.toFixed(3)}]` : '';
      ragContext += col.prefix + ' ' + (i+1) + score + ':\n';
      // Full payload — no truncation for critical keys
      const criticalKeys = ['description','content','summary','analysis','recommendations','elements','factors','eeat_type','niche','city'];
      const otherKeys = Object.keys(p).filter(k => !criticalKeys.includes(k));

      for (const k of criticalKeys) {
        if (p[k]) {
          const val = typeof p[k] === 'string' ? p[k].substring(0, 500) : JSON.stringify(p[k]).substring(0, 500);
          ragContext += '  ' + k + ': ' + val + '\n';
        }
      }
      for (const k of otherKeys.slice(0, 8)) {
        if (p[k]) {
          const val = typeof p[k] === 'string' ? p[k].substring(0, 300) : JSON.stringify(p[k]).substring(0, 300);
          ragContext += '  ' + k + ': ' + val + '\n';
        }
      }
      ragContext += '\n';
    });
  }
}

return [{ json: {
  rag_context: ragContext || 'Нет данных из базы знаний.',
  rag_total_sources: totalSources,
  rag_source_counts: sourceCounts
}}];

const validate = $('Validate & Sanitize Input').first().json;

// Collect RAG context
let ragInfo;
try { ragInfo = $('Format RAG Context').first().json; } catch(e) { ragInfo = { rag_context: '', rag_total_sources: 0 }; }

// Collect CF
let cfRows;
try { 
  const cfResponse = $('Fetch Commercial Factors').first().json;
  cfRows = cfResponse.list || cfResponse.data || [];
} catch(e) { cfRows = []; }

// Collect previous EEAT for delta
let prevElements = [];
try {
  const prevResponse = $('Fetch Previous EEAT').first().json;
  prevElements = prevResponse.list || prevResponse.data || [];
} catch(e) {}

let cfContext = '';
if (cfRows.length > 0) {
  cfContext = '\n=== КОММЕРЧЕСКИЕ ФАКТОРЫ ПРОЕКТА ===\n';
  cfRows.slice(0, 20).forEach((r, i) => {
    cfContext += (i+1) + '. ' + (r.factor_name||'') + ' [' + (r.factor_type||'') + '] — ' + (r.description||'').substring(0,300) + ' | status: ' + (r.status||'pending') + '\n';
  });
}

let prevContext = '';
if (prevElements.length > 0) {
  prevContext = '\n=== ПРЕДЫДУЩИЙ E-E-A-T АУДИТ (для delta-анализа) ===\n';
  prevElements.slice(0, 20).forEach((r, i) => {
    prevContext += (i+1) + '. ' + (r.element_name||'') + ' [' + (r.eeat_type||'') + '] impact=' + (r.impact||'') + ' status=' + (r.status||'') + ' engine=' + (r.search_engine||'') + '\n';
  });
}

// Phase-specific priorities
const phaseGuidance = {
  setup: 'ФАЗА SETUP: Приоритет на базовые E-E-A-T сигналы — author schema, org schema, about page, contact info, privacy policy. Фундамент доверия.',
  growth: 'ФАЗА GROWTH: Приоритет на экспертность и авторитетность — публикации, кейсы, сертификаты, внешние упоминания, отзывы, Schema расширения.',
  maintenance: 'ФАЗА MAINTENANCE: Приоритет на обновление и мониторинг — актуальность дат, свежесть контента, новые отзывы, мониторинг конкурентов.',
  recovery: 'ФАЗА RECOVERY: Приоритет на восстановление Trust — удаление некачественного контента, усиление авторских сигналов, аудит обратных ссылок.'
};

// Niche cluster specific guidance
const clusterGuidance = {
  commercial_local: 'КЛАСТЕР COMMERCIAL_LOCAL: Критичны — Яндекс.Бизнес [Я], Google Business Profile [G], NAP-консистентность [ОБА], отзывы на площадках [ОБА], сертификаты/лицензии [Я].',
  commercial_national: 'КЛАСТЕР COMMERCIAL_NATIONAL: Критичны — backlink-профиль [G], E-E-A-T авторов [G], ИКС [Я], экспертные публикации [ОБА].',
  ecom: 'КЛАСТЕР ECOM: Критичны — Product Schema [G], отзывы на товары [ОБА], гарантии и возврат [Я], безопасность платежей [ОБА].',
  saas: 'КЛАСТЕР SAAS: Критичны — техническая экспертиза авторов [G], кейсы и case studies [ОБА], интеграции и партнёры [ОБА], документация [G].',
  info: 'КЛАСТЕР INFO: Критичны — авторская экспертиза [G], цитируемость [ОБА], актуальность дат [ОБА], YMYL-сигналы если применимо [G].'
};

const systemPrompt = `Ты PENTA-ROLE EXPERT по System Prompt v4.0: Senior SEO Strategist + Automation Engineer + MLOps + Competitive Intelligence + CRO Analyst.

ЗАДАЧА: Провести E-E-A-T аудит v4.0 для конкретной ниши, города и фазы проекта. Сгенерировать персонализированный чек-лист с маркировкой [Я]/[G]/[ОБА].

${phaseGuidance[validate.project_phase] || phaseGuidance.growth}

${clusterGuidance[validate.niche_cluster] || clusterGuidance.commercial_local}

КОНТЕКСТ ИЗ БАЗЫ ЗНАНИЙ:
${ragInfo.rag_context}
${cfContext}
${prevContext}

CONTENT PROTOCOL v2.0 — учитывай 5 слоёв:
1. Релевантность: E-E-A-T элементы должны усиливать тематическую релевантность
2. Читаемость: рекомендации должны быть понятны для внедрения
3. E-E-A-T контент: факты с источниками, авторство, цитируемые данные
4. AEO/GEO: FAQ-структура, Schema FAQPage, Speakable, cite-friendly факты
5. AI Detection: рекомендации по humanization UGC-стиля

МАРКИРОВКА ПОИСКОВЫХ СИСТЕМ — ОБЯЗАТЕЛЬНА для КАЖДОГО элемента:
[Я] — специфично для Яндекса (ИКС, ПФ, КФ, Тематический индекс)
[G] — специфично для Google (E-E-A-T, CWV, HCU, SGE)
[ОБА] — универсально для обоих

МАРКИРОВКА УВЕРЕННОСТИ — для каждого элемента:
verified — подтверждено кейсами
reasoned — логически выведено
hypothesis — требует проверки

ФОРМАТ ОТВЕТА — строго JSON без markdown:
{
  "eeat_elements": [
    {
      "element_name": "Конкретное название",
      "eeat_type": "experience|expertise|authority|trust",
      "description": "Детальная рекомендация для этой ниши и фазы (3-4 предложения)",
      "implementation_steps": ["Шаг 1", "Шаг 2", "Шаг 3"],
      "priority": 1,
      "impact": "high|medium|low",
      "search_engine": "yandex|google|both",
      "estimated_effort": "low|medium|high",
      "confidence": "verified|reasoned|hypothesis",
      "content_layer": "relevance|readability|eeat|aeo_geo|humanization",
      "attribution_metric": "Какой KPI отслеживать для оценки эффекта"
    }
  ],
  "ymyl_score": 0-10,
  "top3_quick_wins": ["Элемент 1", "Элемент 2", "Элемент 3"],
  "delta_vs_previous": "Краткий анализ изменений vs предыдущий аудит (если есть данные)",
  "phase_recommendations": "Рекомендации специфичные для текущей фазы проекта"
}`;

const userPrompt = `НИША: ${validate.niche}
КЛАСТЕР НИШИ: ${validate.niche_cluster}
ГОРОД: ${validate.city}
ФАЗА ПРОЕКТА: ${validate.project_phase}
${validate.target_url ? 'ЦЕЛЕВОЙ URL: ' + validate.target_url : ''}
${validate.competitors.length > 0 ? 'КОНКУРЕНТЫ: ' + validate.competitors.join(', ') : ''}
Коммерческих факторов в базе: ${cfRows.length}
Предыдущих E-E-A-T элементов: ${prevElements.length}
RAG-источников: ${ragInfo.rag_total_sources}

Сгенерируй 16-24 элемента E-E-A-T. Распредели равномерно: 4-6 experience, 4-6 expertise, 4-6 authority, 4-6 trust.
Каждый элемент ОБЯЗАТЕЛЬНО маркируй search_engine: yandex|google|both.
Учитывай фазу проекта ${validate.project_phase} при назначении приоритетов.
Если есть данные предыдущего аудита — укажи delta_vs_previous.
Ответь строго JSON.`;

const payload = {
  model: 'llama-3.3-70b-versatile',
  max_tokens: 8192,
  temperature: 0.2,
  top_p: 0.85,
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ]
};

return [{ json: {
  groq_payload: payload,
  project_id: validate.project_id,
  niche: validate.niche,
  niche_cluster: validate.niche_cluster,
  city: validate.city,
  project_phase: validate.project_phase,
  target_url: validate.target_url,
  cf_count: cfRows.length,
  prev_eeat_count: prevElements.length,
  prev_elements: prevElements,
  rag_total_sources: ragInfo.rag_total_sources
}}];

const groqResponse = $input.first().json;
const batchInfo = $('Build EEAT Prompt v4.0').first().json;

if (groqResponse.error) {
  throw new Error('Groq API error: ' + (groqResponse.error.message || JSON.stringify(groqResponse.error)));
}

const rawContent = groqResponse?.choices?.[0]?.message?.content || '';
let cleanJson = rawContent.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleanJson);
} catch (err) {
  const objMatch = cleanJson.match(/\{[\s\S]*"eeat_elements"[\s\S]*\}/);
  if (objMatch) {
    try { parsed = JSON.parse(objMatch[0]); } catch(e2) {}
  }
  if (!parsed) {
    const arrMatch = cleanJson.match(/\[[\s\S]+\]/);
    if (arrMatch) {
      try { parsed = { eeat_elements: JSON.parse(arrMatch[0]) }; } catch(e3) {}
    }
  }
  if (!parsed) {
    throw new Error('Failed to parse LLM JSON. Raw preview: ' + rawContent.substring(0, 500));
  }
}

if (Array.isArray(parsed)) parsed = { eeat_elements: parsed };

const validTypes = ['experience', 'expertise', 'authority', 'trust'];
const validImpact = ['high', 'medium', 'low'];
const validEngines = ['yandex', 'google', 'both'];
const validEffort = ['low', 'medium', 'high'];
const validConfidence = ['verified', 'reasoned', 'hypothesis'];
const validLayers = ['relevance', 'readability', 'eeat', 'aeo_geo', 'humanization'];

const elements = (parsed.eeat_elements || []).map((el, idx) => ({
  project_id: batchInfo.project_id,
  niche: batchInfo.niche,
  niche_cluster: batchInfo.niche_cluster,
  city: batchInfo.city,
  project_phase: batchInfo.project_phase,
  element_name: (el.element_name || 'Элемент ' + (idx+1)).substring(0, 200),
  eeat_type: validTypes.includes(el.eeat_type) ? el.eeat_type : validTypes[idx % 4],
  description: (el.description || '').substring(0, 1500),
  implementation_steps: JSON.stringify(el.implementation_steps || []),
  priority: Math.min(Math.max(parseInt(el.priority) || (idx+1), 1), 24),
  impact: validImpact.includes(el.impact) ? el.impact : 'medium',
  search_engine: validEngines.includes(el.search_engine) ? el.search_engine : 'both',
  estimated_effort: validEffort.includes(el.estimated_effort) ? el.estimated_effort : 'medium',
  confidence: validConfidence.includes(el.confidence) ? el.confidence : 'reasoned',
  content_layer: validLayers.includes(el.content_layer) ? el.content_layer : 'eeat',
  attribution_metric: (el.attribution_metric || '').substring(0, 200),
  status: 'pending',
  version: 'v4.0',
  created_at: new Date().toISOString()
}));

// Distribution check
const dist = { experience: 0, expertise: 0, authority: 0, trust: 0 };
elements.forEach(e => dist[e.eeat_type]++);

// Engine distribution
const engineDist = { yandex: 0, google: 0, both: 0 };
elements.forEach(e => engineDist[e.search_engine]++);

// Confidence distribution
const confDist = { verified: 0, reasoned: 0, hypothesis: 0 };
elements.forEach(e => confDist[e.confidence]++);

return [{ json: {
  elements,
  elements_count: elements.length,
  distribution: dist,
  engine_distribution: engineDist,
  confidence_distribution: confDist,
  ymyl_score: parsed.ymyl_score || null,
  top3_quick_wins: parsed.top3_quick_wins || [],
  delta_vs_previous: parsed.delta_vs_previous || '',
  phase_recommendations: parsed.phase_recommendations || '',
  groq_tokens: groqResponse?.usage?.total_tokens || 0,
  project_id: batchInfo.project_id,
  niche: batchInfo.niche,
  niche_cluster: batchInfo.niche_cluster,
  city: batchInfo.city,
  project_phase: batchInfo.project_phase,
  target_url: batchInfo.target_url,
  prev_elements: batchInfo.prev_elements || []
}}];

const parsed = $input.first().json;
const prevElements = parsed.prev_elements || [];
const newElements = parsed.elements || [];

let delta = {
  new_elements: [],
  removed_elements: [],
  changed_elements: [],
  distribution_delta: {}
};

if (prevElements.length > 0) {
  const prevNames = new Set(prevElements.map(e => e.element_name));
  const newNames = new Set(newElements.map(e => e.element_name));

  delta.new_elements = newElements.filter(e => !prevNames.has(e.element_name)).map(e => e.element_name);
  delta.removed_elements = prevElements.filter(e => !newNames.has(e.element_name)).map(e => e.element_name);

  // Distribution delta
  const prevDist = { experience: 0, expertise: 0, authority: 0, trust: 0 };
  prevElements.forEach(e => { if (prevDist[e.eeat_type] !== undefined) prevDist[e.eeat_type]++; });

  for (const type of ['experience', 'expertise', 'authority', 'trust']) {
    delta.distribution_delta[type] = (parsed.distribution[type] || 0) - (prevDist[type] || 0);
  }
}

return [{ json: {
  ...parsed,
  delta,
  has_previous: prevElements.length > 0,
  prev_count: prevElements.length
}}];

const response = $input.first().json;
const records = response.list || response.data || [];
const ids = records.map(r => r.Id || r.id).filter(Boolean);

return [{ json: {
  ids_to_delete: ids,
  has_records: ids.length > 0,
  delete_url: 'http://nocodb:8080/api/v1/db/data/noco/' + $env.NOCODB_ORG_ID + '/' + $env.NOCODB_EEAT_TABLE,
  token: $env.NOCODB_API_TOKEN
}}];

const p = $('EEAT Delta Analysis').first().json;
const dist = p.distribution || {};
const engineDist = p.engine_distribution || {};
const confDist = p.confidence_distribution || {};

// Calculate balance score (0-1, 1 = perfect balance)
const counts = [dist.experience||0, dist.expertise||0, dist.authority||0, dist.trust||0];
const avg = counts.reduce((a,b) => a+b, 0) / 4;
const variance = counts.reduce((a,b) => a + Math.pow(b - avg, 2), 0) / 4;
const balanceScore = avg > 0 ? Math.max(0, 1 - (Math.sqrt(variance) / avg)) : 0;

// High impact ratio
const highImpact = p.elements.filter(e => e.impact === 'high').length;
const highImpactRatio = p.elements_count > 0 ? highImpact / p.elements_count : 0;

// Engine coverage
const hasYandex = engineDist.yandex > 0 || engineDist.both > 0;
const hasGoogle = engineDist.google > 0 || engineDist.both > 0;
const engineCoverage = (hasYandex ? 0.5 : 0) + (hasGoogle ? 0.5 : 0);

return [{ json: {
  ml_payload: {
    page_slug: p.target_url || '/',
    elements_count: p.elements_count || 0,
    experience_count: dist.experience || 0,
    expertise_count: dist.expertise || 0,
    authority_count: dist.authority || 0,
    trust_count: dist.trust || 0,
    balance_score: parseFloat(balanceScore.toFixed(3)),
    high_impact_ratio: parseFloat(highImpactRatio.toFixed(3)),
    high_impact_count: highImpact,
    ymyl_score: p.ymyl_score || 0,
    engine_yandex: engineDist.yandex || 0,
    engine_google: engineDist.google || 0,
    engine_both: engineDist.both || 0,
    engine_coverage: engineCoverage,
    confidence_verified: confDist.verified || 0,
    confidence_reasoned: confDist.reasoned || 0,
    has_previous: p.has_previous || false,
    delta_new_count: (p.delta?.new_elements || []).length,
    delta_removed_count: (p.delta?.removed_elements || []).length,
    niche_cluster: p.niche_cluster || 'commercial_local',
    project_phase: p.project_phase || 'growth'
  },
  original_data: p
}}];

const p = $('EEAT Delta Analysis').first().json;
const dist = p.distribution || {};
const engineDist = p.engine_distribution || {};

// Build rich summary for embedding
const typeGroups = {};
p.elements.forEach(e => {
  if (!typeGroups[e.eeat_type]) typeGroups[e.eeat_type] = [];
  typeGroups[e.eeat_type].push(e.element_name + ' [' + e.search_engine + '] ' + e.impact);
});

let summary = `E-E-A-T аудит v4.0 | ${p.niche} | ${p.city} | ${p.niche_cluster} | фаза: ${p.project_phase}
Элементов: ${p.elements_count} | YMYL: ${p.ymyl_score || 'N/A'}
Распределение: exp=${dist.experience} expt=${dist.expertise} auth=${dist.authority} trust=${dist.trust}
Движки: Я=${engineDist.yandex||0} G=${engineDist.google||0} ОБА=${engineDist.both||0}`;

for (const [type, items] of Object.entries(typeGroups)) {
  summary += `\n${type.toUpperCase()}: ${items.join('; ')}`;
}

if (p.top3_quick_wins?.length) {
  summary += `\nQuick wins: ${p.top3_quick_wins.join('; ')}`;
}

if (p.delta_vs_previous) {
  summary += `\nDelta: ${p.delta_vs_previous}`;
}

return [{ json: {
  summary_text: summary.substring(0, 2000),
  project_id: p.project_id,
  niche: p.niche,
  niche_cluster: p.niche_cluster,
  city: p.city,
  project_phase: p.project_phase,
  elements_count: p.elements_count,
  distribution: p.distribution,
  engine_distribution: p.engine_distribution
}}];

