const parsed = $('EEAT Delta Analysis').first().json;
const validate = $('Validate & Sanitize Input').first().json;
const ragInfo = $('Format RAG Context').first().json;

// ML results
let mlScore = null, mlLabel = null, mlConfidence = null;
try {
  const ml = $('ML EEAT Completeness').first().json;
  mlScore = ml.score ?? null;
  mlLabel = ml.label ?? null;
  mlConfidence = ml.confidence ?? null;
} catch(e) {}

// Storage status
let nocodbOk = false, qdrantOk = false;
try { 
  const n = $('Insert EEAT Records').first().json;
  nocodbOk = Array.isArray(n) ? n.length > 0 : !!n;
} catch(e) {}
try {
  const q = $('Save to Qdrant').first().json;
  qdrantOk = q?.result?.status === 'acknowledged' || q?.status === 'ok' || !!q?.result;
} catch(e) {}

return [{ json: {
  status: 'success',
  step: '06_eeat',
  version: 'v4.0_pro',
  project_id: validate.project_id,
  niche: validate.niche,
  niche_cluster: validate.niche_cluster,
  city: validate.city,
  project_phase: validate.project_phase,

  // Analysis results
  elements_count: parsed.elements_count,
  distribution: parsed.distribution,
  engine_distribution: parsed.engine_distribution,
  confidence_distribution: parsed.confidence_distribution,
  ymyl_score: parsed.ymyl_score,
  top3_quick_wins: parsed.top3_quick_wins,
  delta_vs_previous: parsed.delta_vs_previous,
  phase_recommendations: parsed.phase_recommendations,

  // Delta analysis
  delta: parsed.delta,
  has_previous: parsed.has_previous,

  // ML enrichment
  ml_eeat_score: mlScore,
  ml_eeat_label: mlLabel,
  ml_confidence: mlConfidence,

  // Data sources
  rag_total_sources: ragInfo.rag_total_sources,
  rag_source_counts: ragInfo.rag_source_counts,
  groq_tokens: parsed.groq_tokens,

  // Storage status
  nocodb_saved: nocodbOk,
  qdrant_saved: qdrantOk,

  // Elements preview (first 5)
  elements_preview: parsed.elements.slice(0, 5).map(e => ({
    name: e.element_name,
    type: e.eeat_type,
    priority: e.priority,
    impact: e.impact,
    engine: e.search_engine,
    confidence: e.confidence
  })),

  // Attribution data
  attribution: {
    workflow_id: '06',
    workflow_name: 'E-E-A-T Audit v4.0',
    version: 'v4.0',
    affected_pages: validate.target_url ? [validate.target_url] : ['all'],
    elements_generated: parsed.elements_count,
    engine_split: parsed.engine_distribution
  },

  // Meta
  run_id: validate.run_id,
  started_at: validate.started_at,
  completed_at: new Date().toISOString()
}}];

