parameters.jsCode:
const error = $input.first().json;
let validate = {};
try { validate = $('Validate & Sanitize Input').first().json; } catch(e) {}

return [{ json: {
  status: 'error',
  step: '06_eeat',
  version: 'v4.0_pro',
  project_id: validate.project_id || 'unknown',
  niche: validate.niche || 'unknown',
  error_message: error.execution?.error?.message || error.message || 'Unknown error',
  error_node: error.execution?.lastNodeExecuted || 'unknown',
  error_timestamp: error.execution?.stoppedAt || new Date().toISOString(),
  run_id: validate.run_id || $execution.id,
  timestamp: new Date().toISOString()
}}];
